44	      // deno vscode extension to easily pick this up, copy the executable
45	      // into the deno package folder
46	      hardLinkOrCopy(sourceExecutablePath, targetExecutablePath);
47	      if (os.platform() !== "win32") {
48	        // chmod +x
49	        chmodX(targetExecutablePath);
